import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import NavbarGestionSalas from '../components/NavbarGestionSalas';
import { useAuth } from "../context/AuthContext";
import axios from "axios";

import '../styles/GestionarReservas.css'; 
import devolver from '../assets/images/devolver.png';

function GestionarReservas() {
  const { user } = useAuth();
  const [selectedDate, setSelectedDate] = useState(null);
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [showCrear, setShowCrear] = useState(false);

  const [horaInicio, setHoraInicio] = useState("07:00 AM");
  const [horaFin, setHoraFin] = useState("07:30 AM");
  const [salas, setSalas] = useState([]);
  const [salaSeleccionada, setSalaSeleccionada] = useState("");

  const [reservasDelDia, setReservasDelDia] = useState([]);

  // 🔥 OBTENER RESERVAS DEL DÍA (FIX FECHA)
  useEffect(() => {
    if (!selectedDate) return;

    const fetchReservasDelDia = async () => {
      try {
        const fechaStr = selectedDate.toLocaleDateString('en-CA'); // ✅ FIX
        const res = await axios.get(`http://localhost:3001/api/reservas?fecha=${fechaStr}`);
        setReservasDelDia(res.data);
      } catch (error) {
        console.error("Error al obtener reservas:", error);
        setReservasDelDia([]);
      }
    };

    fetchReservasDelDia();
  }, [selectedDate]);

  // 🔹 Obtener salas
  useEffect(() => {
    const fetchSalas = async () => {
      try {
        const res = await axios.get("http://localhost:3001/api/salas");
        setSalas(res.data);
      } catch (error) {
        console.error("Error al obtener salas:", error);
      }
    };
    fetchSalas();
  }, []);

  // 🔹 Generar calendario
  const getDaysInMonth = (date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const days = [];

    const firstDayOfWeek = firstDay.getDay();
    for (let i = firstDayOfWeek - 1; i >= 0; i--) {
      const prevDate = new Date(year, month, -i);
      days.push({ date: prevDate, isCurrentMonth: false });
    }

    for (let i = 1; i <= lastDay.getDate(); i++) {
      days.push({ date: new Date(year, month, i), isCurrentMonth: true });
    }

    return days;
  };

  const days = getDaysInMonth(currentMonth);

  const monthNames = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];
  const dayNames = ["Dom","Lun","Mar","Mié","Jue","Vie","Sáb"];

  const handlePrevMonth = () => {
    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1));
    setSelectedDate(null);
  };

  const handleNextMonth = () => {
    setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1));
    setSelectedDate(null);
  };

  const handleDateClick = (date) => {
    setSelectedDate(date);
  };

  const isSameDate = (d1, d2) => {
    if (!d1 || !d2) return false;
    return d1.getDate() === d2.getDate() &&
           d1.getMonth() === d2.getMonth() &&
           d1.getFullYear() === d2.getFullYear();
  };

  // 🔹 CREAR RESERVA
  const handleCrearReserva = async () => {
    if (!selectedDate) return alert("Selecciona una fecha");
    if (!salaSeleccionada) return alert("Selecciona una sala");

    try {
      const formatoHora = (hora) => {
        const [time, ampm] = hora.split(" ");
        let [h, m] = time.split(":").map(Number);
        if (ampm === "PM" && h !== 12) h += 12;
        if (ampm === "AM" && h === 12) h = 0;
        return { h, m };
      };

      const inicio = formatoHora(horaInicio);
      const fin = formatoHora(horaFin);

      const fechaInicio = new Date(selectedDate);
      fechaInicio.setHours(inicio.h, inicio.m, 0, 0);

      const fechaFin = new Date(selectedDate);
      fechaFin.setHours(fin.h, fin.m, 0, 0);

      await axios.post("http://localhost:3001/api/reservas", {
        fechaInicio,
        fechaFin,
        idUsuario: user.id,
        idSala: salaSeleccionada
      });

      alert("Reserva creada correctamente");
      setShowCrear(false);

      // 🔥 RECARGAR RESERVAS
      const fechaStr = selectedDate.toLocaleDateString('en-CA');
      const res = await axios.get(`http://localhost:3001/api/reservas?fecha=${fechaStr}`);
      setReservasDelDia(res.data);

    } catch (error) {
      console.error(error);
      alert("Error al crear reserva");
    }
  };

  return (
    <div className="grContainer">
      <NavbarGestionSalas userRole={user?.rol || ""} />

      <div className="grContent">
        <div className="threeColumnLayout">

          {/* IZQUIERDA */}
          <div className="leftColumnSelected">
            <div className="selectedDateCard">
              <h3>Fecha Seleccionada</h3>

              {selectedDate ? (
                <p>{selectedDate.toLocaleDateString()}</p>
              ) : (
                <p>No hay fecha seleccionada</p>
              )}
            </div>

            <div className="secondaryCard">
              <h4>Reservas del día</h4>

              {reservasDelDia.length === 0 ? (
                <p>No hay reservas</p>
              ) : (
                <ul>
                  {reservasDelDia.map(r => (
                    <li key={r.id}>
                      Sala {r.idSala} | 
                      {new Date(r.fechaInicio).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                      -
                      {new Date(r.fechaFin).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>

          {/* CENTRO CALENDARIO */}
          <div className="calendarColumn">
            <div className="calendarHeader">
              <button onClick={handlePrevMonth}>◀</button>
              <h3>{monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}</h3>
              <button onClick={handleNextMonth}>▶</button>
            </div>

            <div className="calendarGrid">
              {dayNames.map(d => <div key={d}>{d}</div>)}

              {days.map((day, i) => (
                <div
                  key={i}
                  className={`calendarDay ${isSameDate(day.date, selectedDate) ? "selected" : ""}`}
                  onClick={() => handleDateClick(day.date)}
                >
                  {day.date.getDate()}
                </div>
              ))}
            </div>
          </div>

          {/* DERECHA */}
          <div className="rightColumn">
            <button onClick={() => setShowCrear(true)}>Crear Reserva</button>

            {showCrear && (
              <div className="modal">
                <h3>Nueva Reserva</h3>

                <select onChange={(e) => setSalaSeleccionada(e.target.value)}>
                  <option value="">Seleccionar sala</option>
                  {salas.map(s => (
                    <option key={s.id} value={s.id}>{s.nombre}</option>
                  ))}
                </select>

                <input value={horaInicio} onChange={e => setHoraInicio(e.target.value)} />
                <input value={horaFin} onChange={e => setHoraFin(e.target.value)} />

                <button onClick={handleCrearReserva}>Guardar</button>
              </div>
            )}
          </div>

        </div>
      </div>

      <div className="footerRojo">
        <Link to="/inicio/GSInicio">
          <img src={devolver} alt="volver" />
        </Link>
      </div>
    </div>
  );
}

export default GestionarReservas;
